/**
 * @brief Calculates the minimum stable index.
 * 
 * @param nums The input array of integers.
 * @param k The threshold value.
 * @return int64 The smallest stable index, or -1 if none exists.
 */
int64 solve(const std::vector<int64>& nums, int64 k) {
    int n = nums.size();

    // Precompute prefix maximums: prefix_max[i] = max(nums[0...i])
    std::vector<int64> prefix_max(n);
    prefix_max[0] = nums[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], nums[i]);
    }

    // Precompute suffix minimums: suffix_min[i] = min(nums[i...n-1])
    std::vector<int64> suffix_min(n);
    suffix_min[n - 1] = nums[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_min[i] = std::min(suffix_min[i + 1], nums[i]);
    }

    // Iterate through all indices i to find the smallest stable index
    for (int i = 0; i < n; ++i) {
        // Unstable value for index i: max(nums[0..i]) - min(nums[i..n-1])
        int64 unstable_value = prefix_max[i] - suffix_min[i];

        // Check if it is a stable index
        if (unstable_value <= k) {
            return (int64)i;
        }
    }

    // If no stable index is found
    return -1;
}
